floor-ceil-in-sorted-array.code:
#include <bits/stdc++.h>
using namespace std;

pair<int, int> floorCeilLinear(const vector<int>& values, int target) {
    int floorValue = INT_MIN;
    int ceilValue = INT_MAX;
    for (int value : values) {
        if (value <= target)
            floorValue = max(floorValue, value);
        if (value >= target)
            ceilValue = min(ceilValue, value);
    }
    return {floorValue == INT_MIN ? -1 : floorValue, ceilValue == INT_MAX ? -1 : ceilValue};
}

int main() {
    vector<int> values = {1, 2, 4, 6, 8};
    auto answer = floorCeilLinear(values, 5);
    cout << answer.first << " " << answer.second << "\n";
    return 0;
}

