int shippingDays(const vector<int>& weights, int capacity) {
    int days = 1, load = 0;
    for (int weight : weights) {
        if (load + weight > capacity) {
            ++days;
            load = 0;
        }
        load += weight;
    }
    return days;
}

int shipCapacityBrute(const vector<int>& weights, int days) {
    int low = *max_element(weights.begin(), weights.end());
    int high = accumulate(weights.begin(), weights.end(), 0);
    for (int capacity = low; capacity <= high; ++capacity) {
        if (shippingDays(weights, capacity) <= days)
            return capacity;
    }
    return high;
}

