vector<pair<int, int>> frequenciesBrute(const vector<int>& values) {
    vector<pair<int, int>> result;
    vector<bool> processed(values.size(), false);
    for (int index = 0; index < (int)values.size(); ++index) {
        if (processed[index])
            continue;
        int count = 0;
        for (int other = 0; other < (int)values.size(); ++other) {
            if (values[other] == values[index]) {
                ++count;
                processed[other] = true;
            }
        }
        result.push_back({values[index], count});
    }
    return result;
}

int main() {
