const int INF = 1000000000;
int solve(int index, int amount, const vector<int>& coins) {
    if (amount == 0)
        return 0;
    if (index < 0)
        return INF;
    int skip = solve(index - 1, amount, coins), take = INF;
    if (coins[index] <= amount)
        take = 1 + solve(index, amount - coins[index], coins);
    return min(skip, take);
}
