int lis(int index, int previous, const vector<int>& values) {
    if (index == (int)values.size())
        return 0;
    int skip = lis(index + 1, previous, values), take = 0;
    if (previous == -1 || values[index] > values[previous])
        take = 1 + lis(index + 1, index, values);
    return max(skip, take);
}
