#include <bits/stdc++.h>
using namespace std;

long long solve(int left, int right, const vector<int>& dimensions) {
    if (left == right)
        return 0;
    long long answer = LLONG_MAX;
    for (int split = left; split < right; ++split)
        answer =
            min(answer, solve(left, split, dimensions) + solve(split + 1, right, dimensions) +
                            1LL * dimensions[left - 1] * dimensions[split] * dimensions[right]);
    return answer;
}
