        return 0;
    if (buy)
        return max(-prices[day] + solve(day + 1, 0, prices, fee), solve(day + 1, 1, prices, fee));
    return max(prices[day] - fee + solve(day + 1, 1, prices, fee), solve(day + 1, 0, prices, fee));
}
