#include <bits/stdc++.h>
using namespace std;

int burst(vector<int> balloons) {
    if (balloons.empty())
        return 0;
    int answer = 0;
    for (int index = 0; index < (int)balloons.size(); ++index) {
        int left = index == 0 ? 1 : balloons[index - 1],
            right = index + 1 == (int)balloons.size() ? 1 : balloons[index + 1];
        vector<int> remaining = balloons;
        remaining.erase(remaining.begin() + index);
        answer = max(answer, left * balloons[index] * right + burst(remaining));
    }
    return answer;
}
