#include <bits/stdc++.h>
using namespace std;

vector<pair<int, int>> mergeSlow(vector<pair<int, int>> intervals) {
    bool changed = true;
    while (changed) {
        changed = false;
        for (int i = 0; i < (int)intervals.size() && !changed; ++i) {
            for (int j = i + 1; j < (int)intervals.size(); ++j) {
                if (max(intervals[i].first, intervals[j].first) <=
                    min(intervals[i].second, intervals[j].second)) {
                    intervals[i] = {min(intervals[i].first, intervals[j].first),
                                    max(intervals[i].second, intervals[j].second)};
                    intervals.erase(intervals.begin() + j);
                    changed = true;
                    break;
                }
            }
        }
    }
    sort(intervals.begin(), intervals.end());
    return intervals;
}
int main() {
