#include <bits/stdc++.h>
using namespace std;

struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int value) : value(value), left(nullptr), right(nullptr) {
    }
};
int depth(Node* root) {
    if (!root)
        return 0;
    queue<Node*> pending;
    pending.push(root);
    int levels = 0;
    while (!pending.empty()) {
        int width = pending.size();
        ++levels;
        while (width--) {
            Node* node = pending.front();
            pending.pop();
            if (node->left)
                pending.push(node->left);
            if (node->right)
                pending.push(node->right);
        }
    }
    return levels;
}
