#include <bits/stdc++.h>
using namespace std;

struct Node {
    int value;
    vector<Node*> neighbors;
    explicit Node(int value) : value(value) {
    }
};
Node* cloneGraph(Node* start) {
    if (!start)
        return nullptr;
    unordered_map<Node*, Node*> copy;
    copy[start] = new Node(start->value);
    queue<Node*> pending;
    pending.push(start);
    while (!pending.empty()) {
        Node* node = pending.front();
        pending.pop();
        for (Node* next : node->neighbors) {
            if (!copy.count(next)) {
                copy[next] = new Node(next->value);
                pending.push(next);
            }
            copy[node]->neighbors.push_back(copy[next]);
        }
    }
    return copy[start];
}
int main() {
    Node* a = new Node(1);
    Node* b = new Node(2);
    a->neighbors = {b};
    b->neighbors = {a};
    cout << cloneGraph(a)->neighbors[0]->value << "\n";
    return 0;
}

