dijkstra-s-algorithm.code:
#include <bits/stdc++.h>
using namespace std;

vector<int> dijkstra(const vector<vector<int>>& weight, int source) {
    int n = weight.size();
    vector<int> distance(n, INT_MAX);
    vector<bool> used(n);
    distance[source] = 0;
    for (int step = 0; step < n; ++step) {
        int node = -1;
        for (int i = 0; i < n; ++i)
            if (!used[i] && (node == -1 || distance[i] < distance[node]))
                node = i;
        if (node == -1 || distance[node] == INT_MAX)
            break;
        used[node] = true;
        for (int next = 0; next < n; ++next)
            if (weight[node][next] >= 0)
                distance[next] = min(distance[next], distance[node] + weight[node][next]);
    }
    return distance;
}
int main() {
    vector<vector<int>> graph = {{0, 4, 1}, {-1, 0, 2}, {-1, 1, 0}};
    for (int value : dijkstra(graph, 0))
        cout << value << " ";
