#include <bits/stdc++.h>
using namespace std;

vector<vector<int>> fill(vector<vector<int>> image, int sr, int sc, int color) {
    int original = image[sr][sc];
    if (original == color)
        return image;
    int rows = image.size(), columns = image[0].size(), move[5] = {-1, 0, 1, 0, -1};
    queue<pair<int, int>> pending;
    pending.push({sr, sc});
    image[sr][sc] = color;
    while (!pending.empty()) {
        pair<int, int> cell = pending.front();
        int r = cell.first, c = cell.second;
        pending.pop();
        for (int d = 0; d < 4; ++d) {
            int nr = r + move[d], nc = c + move[d + 1];
            if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && image[nr][nc] == original) {
                image[nr][nc] = color;
                pending.push({nr, nc});
            }
        }
    }
    return image;
}
