#include <bits/stdc++.h>
using namespace std;

vector<int> topological(const vector<vector<int>>& graph) {
    vector<int> indegree(graph.size());
    for (auto& edges : graph)
        for (int next : edges)
            ++indegree[next];
    queue<int> pending;
    for (int node = 0; node < (int)graph.size(); ++node)
        if (indegree[node] == 0)
            pending.push(node);
    vector<int> order;
    while (!pending.empty()) {
        int node = pending.front();
        pending.pop();
        order.push_back(node);
        for (int next : graph[node])
            if (--indegree[next] == 0)
                pending.push(next);
    }
    return order;
}
int main() {
