bool cyclic(const vector<vector<int>>& graph) {
    vector<bool> seen(graph.size());
    for (int start = 0; start < (int)graph.size(); ++start)
        if (!seen[start]) {
            queue<pair<int, int>> pending;
            pending.push({start, -1});
            seen[start] = true;
            while (!pending.empty()) {
                pair<int, int> state = pending.front();
                int node = state.first, parent = state.second;
                pending.pop();
                for (int next : graph[node]) {
                    if (!seen[next]) {
                        seen[next] = true;
                        pending.push({next, node});
                    } else if (next != parent)
                        return true;
                }
            }
        }
    return false;
}
