int startStation(const vector<int>& gas, const vector<int>& cost) {
    int n = gas.size();
    for (int start = 0; start < n; ++start) {
        int fuel = 0, steps = 0;
        while (steps < n) {
            int station = (start + steps) % n;
            fuel += gas[station] - cost[station];
            if (fuel < 0)
                break;
            ++steps;
        }
        if (steps == n)
            return start;
    }
    return -1;
}
