    }
};
Node* addOne(Node* head) {
    vector<Node*> digits;
    for (Node* node = head; node; node = node->next)
        digits.push_back(node);
    int carry = 1;
    for (int i = (int)digits.size() - 1; i >= 0 && carry; --i) {
        int sum = digits[i]->value + carry;
        digits[i]->value = sum % 10;
        carry = sum / 10;
    }
    if (carry) {
        Node* node = new Node(carry);
        node->next = head;
        return node;
    }
    return head;
}
