#include <bits/stdc++.h>
using namespace std;
struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
int kthSmallest(Node* root, int k) {
    stack<Node*> pending;
    while (root || !pending.empty()) {
        while (root) {
            pending.push(root);
            root = root->left;
        }
        root = pending.top();
        pending.pop();
        if (--k == 0)
            return root->value;
        root = root->right;
    }
    throw out_of_range("k");
}
