int match(int child, const vector<int>& greed, const vector<int>& cookies, vector<bool>& used) {
    if (child == (int)greed.size())
        return 0;
    int best = match(child + 1, greed, cookies, used);
    for (int i = 0; i < (int)cookies.size(); ++i)
        if (!used[i] && cookies[i] >= greed[child]) {
            used[i] = true;
            best = max(best, 1 + match(child + 1, greed, cookies, used));
            used[i] = false;
        }
    return best;
}
