    for (int width = 1; width < (int)values.size(); width *= 2) {
        for (int left = 0; left < (int)values.size(); left += 2 * width) {
            int middle = min(left + width, (int)values.size()),
                right = min(left + 2 * width, (int)values.size());
            merge(values.begin() + left, values.begin() + middle, values.begin() + middle,
                  values.begin() + right, buffer.begin() + left);
        }
