   public:
    void push(int value) {
        while (!ready.empty()) {
            buffer.push(ready.top());
            ready.pop();
        }
        ready.push(value);
        while (!buffer.empty()) {
            ready.push(buffer.top());
            buffer.pop();
        }
    }
    int pop() {
        int value = ready.top();
        ready.pop();
        return value;
    }
