lru-cache.code:
#include <bits/stdc++.h>
using namespace std;
class LRUCache {
    int capacity, clock = 0;
    unordered_map<int, pair<int, int>> data;

   public:
    explicit LRUCache(int size) : capacity(size) {
    }
    int get(int key) {
        if (!data.count(key))
            return -1;
        data[key].second = ++clock;
        return data[key].first;
    }
    void put(int key, int value) {
        if (!data.count(key) && data.size() == (size_t)capacity) {
            auto victim = min_element(data.begin(), data.end(), [](auto& a, auto& b) {
                return a.second.second < b.second.second;
            });
            data.erase(victim);
        }
        data[key] = {value, ++clock};
    }
};
int main() {
    LRUCache cache(2);
    cache.put(1, 10);
    cache.put(2, 20);
    cache.get(1);
    cache.put(3, 30);
    cout << cache.get(2);
    return 0;
}

