#include <bits/stdc++.h>
using namespace std;
vector<vector<int>> distanceToZero(const vector<vector<int>>& grid) {
    int rows = grid.size(), columns = grid[0].size(), move[5] = {-1, 0, 1, 0, -1};
    vector<vector<int>> answer(rows, vector<int>(columns));
    for (int sr = 0; sr < rows; ++sr)
        for (int sc = 0; sc < columns; ++sc)
            if (grid[sr][sc]) {
                queue<pair<int, int>> pending;
                vector<vector<int>> distance(rows, vector<int>(columns, -1));
                pending.push({sr, sc});
                distance[sr][sc] = 0;
                while (!pending.empty()) {
                    auto codeverseItem0 = pending.front();
                    auto r = codeverseItem0.first;
                    auto c = codeverseItem0.second;
                    pending.pop();
                    if (!grid[r][c]) {
                        answer[sr][sc] = distance[r][c];
                        break;
                    }
                    for (int d = 0; d < 4; ++d) {
                        int nr = r + move[d], nc = c + move[d + 1];
                        if (nr >= 0 && nr < rows && nc >= 0 && nc < columns &&
                            distance[nr][nc] < 0) {
                            distance[nr][nc] = distance[r][c] + 1;
                            pending.push({nr, nc});
                        }
                    }
                }
            }
    return answer;
}
int main() {
    for (auto& row : distanceToZero({{0, 0, 0}, {0, 1, 0}, {1, 1, 1}})) {
        for (int value : row)
            cout << value << " ";
        cout << "\n";
    }
    return 0;
}

