long long splitArray(const vector<int>& values, int groups) {
    int n = values.size();
    vector<long long> prefix(n + 1);
    for (int i = 0; i < n; ++i)
        prefix[i + 1] = prefix[i] + values[i];
    const long long INF = LLONG_MAX / 4;
    vector<vector<long long>> dp(groups + 1, vector<long long>(n + 1, INF));
    dp[0][0] = 0;
    for (int g = 1; g <= groups; ++g)
        for (int end = 1; end <= n; ++end)
            for (int cut = g - 1; cut < end; ++cut)
                dp[g][end] = min(dp[g][end], max(dp[g - 1][cut], prefix[end] - prefix[cut]));
    return dp[groups][n];
}
