    }
};
Node* deleteMiddle(Node* head) {
    if (!head || !head->next)
        return nullptr;
    int length = 0;
    for (Node* node = head; node; node = node->next)
        ++length;
    Node* node = head;
    for (int step = 1; step < length / 2; ++step)
        node = node->next;
    node->next = node->next->next;
    return head;
}
