#include <bits/stdc++.h>
using namespace std;
void choose(const string& digits, int index, int need, string& current, string& best) {
    if (need == 0) {
        size_t first = current.find_first_not_of('0');
        string value = first == string::npos ? "0" : current.substr(first);
        if (best.empty() || value.size() < best.size() ||
            (value.size() == best.size() && value < best))
            best = value;
        return;
    }
    if ((int)digits.size() - index < need)
        return;
    current.push_back(digits[index]);
    choose(digits, index + 1, need - 1, current, best);
    current.pop_back();
    choose(digits, index + 1, need, current, best);
}
string removeK(const string& digits, int k) {
    string current, best;
    choose(digits, 0, digits.size() - k, current, best);
    return best;
}
