task-scheduler.code:
#include <bits/stdc++.h>
using namespace std;
int leastInterval(const vector<char>& tasks, int cooldown) {
    array<int, 26> count{};
    for (char task : tasks)
        ++count[task - 'A'];
    priority_queue<int> ready;
    for (int frequency : count)
        if (frequency)
            ready.push(frequency);
    queue<pair<int, int>> waiting;
    int time = 0;
    while (!ready.empty() || !waiting.empty()) {
        ++time;
        if (!ready.empty()) {
            int remaining = ready.top() - 1;
            ready.pop();
            if (remaining)
                waiting.push({remaining, time + cooldown});
        }
        if (!waiting.empty() && waiting.front().second == time) {
            ready.push(waiting.front().first);
            waiting.pop();
        }
    }
    return time;
}
int main() {
    cout << leastInterval({'A', 'A', 'A', 'B', 'B', 'B'}, 2);
    return 0;
}

