    }
};
void collect(Node* node, int depth, vector<deque<int>>& levels) {
    if (!node)
        return;
    if (depth == (int)levels.size())
        levels.push_back({});
    if (depth % 2)
        levels[depth].push_front(node->value);
    else
        levels[depth].push_back(node->value);
    collect(node->left, depth + 1, levels);
    collect(node->right, depth + 1, levels);
}
