struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
void visit(Node* node, int column, int depth, map<int, pair<int, int>>& view) {
    if (!node)
        return;
