struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
bool symmetric(Node* root) {
    if (!root)
        return true;
    queue<pair<Node*, Node*>> pending;
    pending.push({root->left, root->right});
    while (!pending.empty()) {
        auto codeverseItem0 = pending.front();
        auto a = codeverseItem0.first;
        auto b = codeverseItem0.second;
        pending.pop();
        if (!a || !b) {
            if (a != b)
                return false;
            continue;
        }
        if (a->value != b->value)
            return false;
        pending.push({a->left, b->right});
        pending.push({a->right, b->left});
    }
    return true;
}
int main() {
