#include <bits/stdc++.h>
using namespace std;
bool subsequence(const string& candidate, const string& text) {
    int index = 0;
    for (char ch : text)
        if (index < (int)candidate.size() && candidate[index] == ch)
            ++index;
    return index == (int)candidate.size();
}
string lcs(const string& first, const string& second) {
    const string& small = first.size() <= second.size() ? first : second;
    const string& large = first.size() <= second.size() ? second : first;
    string best;
    for (int mask = 0; mask < (1 << (int)small.size()); ++mask) {
        string candidate;
        for (int bit = 0; bit < (int)small.size(); ++bit)
            if (mask & (1 << bit))
                candidate += small[bit];
        if (candidate.size() > best.size() && subsequence(candidate, large))
            best = candidate;
    }
    return best;
}
int main() {
    cout << lcs("abcde", "ace");
    return 0;
}

reverse-nodes-in-k-group.code:
#include <bits/stdc++.h>
using namespace std;
struct Node {
    int value;
    Node* next;
    explicit Node(int x) : value(x), next(nullptr) {
    }
};
Node* reverseGroups(Node* head, int k) {
    Node dummy(0), *tail = &dummy, *node = head;
    while (node) {
        vector<Node*> group;
        Node* cursor = node;
        for (int i = 0; i < k && cursor; ++i) {
            group.push_back(cursor);
            cursor = cursor->next;
        }
        if ((int)group.size() < k) {
            tail->next = node;
            break;
        }
        for (int i = k - 1; i >= 0; --i) {
            tail->next = group[i];
            tail = tail->next;
        }
        tail->next = cursor;
        node = cursor;
    }
    return dummy.next;
}
int main() {
    Node a(1), b(2), c(3), d(4);
    a.next = &b;
    b.next = &c;
    c.next = &d;
    for (Node* n = reverseGroups(&a, 2); n; n = n->next)
        cout << n->value << " ";
    return 0;
}

