struct Node {
    int value;
    Node* next;
    Node* down;
    explicit Node(int x) : value(x), next(nullptr), down(nullptr) {
    }
};
Node* flatten(Node* head) {
    priority_queue<pair<int, Node*>, vector<pair<int, Node*>>, greater<pair<int, Node*>>> pending;
    for (Node* node = head; node; node = node->next)
        pending.push({node->value, node});
    Node dummy(0), *tail = &dummy;
    while (!pending.empty()) {
        Node* node = pending.top().second;
        pending.pop();
        tail->down = node;
        tail = node;
        if (node->down)
            pending.push({node->down->value, node->down});
        tail->next = nullptr;
    }
    return dummy.down;
}
