#include <bits/stdc++.h>
using namespace std;
bool connected(int start, int target, const vector<vector<int>>& graph, pair<int, int> removed) {
    queue<int> pending;
    vector<bool> seen(graph.size());
    pending.push(start);
    seen[start] = true;
    while (!pending.empty()) {
        int node = pending.front();
        pending.pop();
        if (node == target)
            return true;
        for (int next : graph[node])
            if (!seen[next] && !((node == removed.first && next == removed.second) ||
                                 (node == removed.second && next == removed.first))) {
                seen[next] = true;
                pending.push(next);
            }
    }
    return false;
}
vector<pair<int, int>> bridges(const vector<vector<int>>& graph) {
    vector<pair<int, int>> answer;
    for (int node = 0; node < (int)graph.size(); ++node)
        for (int next : graph[node])
            if (node < next && !connected(node, next, graph, {node, next}))
                answer.push_back({node, next});
    return answer;
}
int main() {
    vector<vector<int>> graph = {{1}, {0, 2}, {1}};
    for (const auto& codeverseItem0 : bridges(graph)) {
        auto a = codeverseItem0.first;
        auto b = codeverseItem0.second;
        cout << a << "-" << b << " ";
    }
    return 0;
}

