#include <bits/stdc++.h>
using namespace std;
int components(const vector<vector<int>>& graph, int removed) {
    vector<bool> seen(graph.size());
    int count = 0;
    for (int start = 0; start < (int)graph.size(); ++start)
        if (start != removed && !seen[start]) {
            ++count;
            stack<int> pending;
            pending.push(start);
            seen[start] = true;
            while (!pending.empty()) {
                int node = pending.top();
                pending.pop();
                for (int next : graph[node])
                    if (next != removed && !seen[next]) {
                        seen[next] = true;
                        pending.push(next);
                    }
            }
        }
    return count;
}
vector<int> articulation(const vector<vector<int>>& graph) {
    int baseline = components(graph, -1);
    vector<int> answer;
    for (int node = 0; node < (int)graph.size(); ++node)
        if (components(graph, node) > baseline)
            answer.push_back(node);
    return answer;
}
int main() {
    vector<vector<int>> graph = {{1}, {0, 2, 3}, {1}, {1}};
    for (int node : articulation(graph))
        cout << node << " ";
    return 0;
}

