    int profit;
};
pair<int, int> schedule(vector<Job> jobs) {
    sort(jobs.begin(), jobs.end(), [](auto& a, auto& b) { return a.profit > b.profit; });
    int limit = 0;
    for (auto job : jobs)
        limit = max(limit, job.deadline);
    vector<bool> used(limit + 1);
    int count = 0, profit = 0;
    for (auto job : jobs)
        for (int slot = min(limit, job.deadline); slot > 0; --slot)
            if (!used[slot]) {
                used[slot] = true;
                ++count;
                profit += job.profit;
                break;
            }
    return {count, profit};
}
