surrounded-regions.code:
#include <bits/stdc++.h>
using namespace std;
struct DSU {
    vector<int> parent, size;
    explicit DSU(int n) : parent(n), size(n, 1) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    void unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b)
            return;
        if (size[a] < size[b])
            swap(a, b);
        parent[b] = a;
        size[a] += size[b];
    }
};
void solve(vector<vector<char>>& board) {
    int rows = board.size(), columns = board[0].size(), outside = rows * columns,
        moves[5] = {-1, 0, 1, 0, -1};
    DSU dsu(outside + 1);
    for (int r = 0; r < rows; ++r)
        for (int c = 0; c < columns; ++c)
            if (board[r][c] == 'O') {
                int id = r * columns + c;
                if (r == 0 || c == 0 || r + 1 == rows || c + 1 == columns)
                    dsu.unite(id, outside);
                for (int d = 0; d < 4; ++d) {
                    int nr = r + moves[d], nc = c + moves[d + 1];
                    if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && board[nr][nc] == 'O')
                        dsu.unite(id, nr * columns + nc);
                }
            }
    for (int r = 0; r < rows; ++r)
        for (int c = 0; c < columns; ++c)
            if (board[r][c] == 'O' && dsu.find(r * columns + c) != dsu.find(outside))
                board[r][c] = 'X';
}
int main() {
    vector<vector<char>> board = {{'X', 'X', 'X'}, {'X', 'O', 'X'}, {'X', 'X', 'X'}};
    solve(board);
    cout << board[1][1];
    return 0;
}

