#include <bits/stdc++.h>
using namespace std;
int enclaves(const vector<vector<int>>& grid) {
    int rows = grid.size(), columns = grid[0].size(), answer = 0, moves[5] = {-1, 0, 1, 0, -1};
    vector<vector<bool>> seen(rows, vector<bool>(columns));
    for (int sr = 0; sr < rows; ++sr)
        for (int sc = 0; sc < columns; ++sc)
            if (grid[sr][sc] && !seen[sr][sc]) {
                queue<pair<int, int>> pending;
                pending.push({sr, sc});
                seen[sr][sc] = true;
                int cells = 0;
                bool boundary = false;
                while (!pending.empty()) {
                    auto codeverseItem0 = pending.front();
                    auto r = codeverseItem0.first;
                    auto c = codeverseItem0.second;
                    pending.pop();
                    ++cells;
                    boundary = boundary || r == 0 || c == 0 || r + 1 == rows || c + 1 == columns;
                    for (int d = 0; d < 4; ++d) {
                        int nr = r + moves[d], nc = c + moves[d + 1];
                        if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && grid[nr][nc] &&
                            !seen[nr][nc]) {
                            seen[nr][nc] = true;
                            pending.push({nr, nc});
                        }
                    }
                }
                if (!boundary)
                    answer += cells;
            }
    return answer;
}
