int ladder(string begin, string end, vector<string> words) {
    words.push_back(begin);
    int n = words.size(), start = n - 1,
        target = find(words.begin(), words.end(), end) - words.begin();
    if (target == n)
        return 0;
    vector<vector<int>> graph(n);
    for (int i = 0; i < n; ++i)
        for (int j = i + 1; j < n; ++j)
            if (adjacent(words[i], words[j])) {
                graph[i].push_back(j);
                graph[j].push_back(i);
            }
    queue<int> pending;
    vector<int> distance(n, -1);
    pending.push(start);
    distance[start] = 1;
    while (!pending.empty()) {
        int node = pending.front();
        pending.pop();
        if (node == target)
            return distance[node];
        for (int next : graph[node])
            if (distance[next] < 0) {
                distance[next] = distance[node] + 1;
                pending.push(next);
            }
    }
    return 0;
}
int main() {
    cout << ladder("hit", "cog", {"hot", "dot", "dog", "lot", "log", "cog"});
    return 0;
}

