#include <bits/stdc++.h>
using namespace std;
struct Node {
    int value;
    Node* next;
    explicit Node(int x) : value(x), next(nullptr) {
    }
};
Node* add(Node* first, Node* second) {
    stack<int> a, b;
    for (; first; first = first->next)
        a.push(first->value);
    for (; second; second = second->next)
        b.push(second->value);
    Node* head = nullptr;
    int carry = 0;
    while (!a.empty() || !b.empty() || carry) {
        int sum = carry;
        if (!a.empty()) {
            sum += a.top();
            a.pop();
        }
        if (!b.empty()) {
            sum += b.top();
            b.pop();
        }
        Node* node = new Node(sum % 10);
        node->next = head;
        head = node;
        carry = sum / 10;
    }
    return head;
}
