reverse-ll-in-groups-of-size-k.code:
#include <bits/stdc++.h>
using namespace std;
struct Node {
    int value;
    Node* next;
    explicit Node(int x) : value(x), next(nullptr) {
    }
};
Node* reverseK(Node* head, int k) {
    Node dummy(0), *tail = &dummy, *node = head;
    while (node) {
        vector<Node*> group;
        Node* cursor = node;
        for (int i = 0; i < k && cursor; ++i) {
            group.push_back(cursor);
            cursor = cursor->next;
        }
        if ((int)group.size() < k) {
            tail->next = node;
            break;
        }
        for (int i = k - 1; i >= 0; --i) {
            tail->next = group[i];
            tail = tail->next;
        }
        tail->next = cursor;
        node = cursor;
    }
    return dummy.next;
}
int main() {
    Node a(1), b(2), c(3);
    a.next = &b;
    b.next = &c;
    for (Node* n = reverseK(&a, 2); n; n = n->next)
        cout << n->value << " ";
    return 0;
}

