        for (int i = 0; i < vertices; ++i) {
            assignment[i] = value % colors;
            value /= colors;
        }
        bool valid = true;
        for (int node = 0; node < vertices; ++node)
            for (int next : graph[node])
                if (assignment[node] == assignment[next])
                    valid = false;
