string minimumWindow(const string& source, const string& target) {
    int bestStart = -1, bestLength = INT_MAX;
    for (int left = 0; left < (int)source.size(); ++left) {
        int matched = 0;
        for (int right = left; right < (int)source.size(); ++right) {
            if (source[right] == target[matched])
                ++matched;
            if (matched == (int)target.size()) {
                if (right - left + 1 < bestLength) {
                    bestStart = left;
                    bestLength = right - left + 1;
                }
                break;
            }
        }
    }
    return bestStart < 0 ? "" : source.substr(bestStart, bestLength);
}
