    queue<Node*> pending;
    pending.push(root);
    parent[root] = nullptr;
    Node* found = nullptr;
    while (!pending.empty()) {
        Node* node = pending.front();
        pending.pop();
        if (node->value == target) {
            found = node;
            break;
