        for (Node* next : {node->left, node->right})
            if (next) {
                parent[next] = node;
                pending.push(next);
            }
    }
    vector<int> answer;
    for (Node* node = found; node; node = parent[node])
        answer.push_back(node->value);
    reverse(answer.begin(), answer.end());
    return answer;
}
