bool findPath(Node* node, int target, vector<Node*>& path) {
    if (!node)
        return false;
    path.push_back(node);
    if (node->value == target)
        return true;
    if (findPath(node->left, target, path) || findPath(node->right, target, path))
        return true;
    path.pop_back();
    return false;
}
