struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
unsigned long long width(Node* root) {
    if (!root)
        return 0;
    queue<pair<Node*, unsigned long long>> pending;
    pending.push({root, 1});
    unsigned long long best = 0;
    while (!pending.empty()) {
        int count = pending.size();
        unsigned long long first = pending.front().second, last = first;
        while (count--) {
            auto codeverseItem0 = pending.front();
            auto node = codeverseItem0.first;
            auto index = codeverseItem0.second;
            pending.pop();
            last = index;
            if (node->left)
                pending.push({node->left, index * 2});
            if (node->right)
                pending.push({node->right, index * 2 + 1});
        }
        best = max(best, last - first + 1);
    }
    return best;
}
