    unordered_map<Node*, Node*> parent;
    queue<Node*> build;
    build.push(root);
    parent[root] = nullptr;
    while (!build.empty()) {
        Node* node = build.front();
        build.pop();
        for (Node* next : {node->left, node->right})
            if (next) {
                parent[next] = node;
                build.push(next);
            }
    }
    queue<Node*> pending;
    unordered_set<Node*> seen;
    pending.push(target);
    seen.insert(target);
    while (k--) {
        int count = pending.size();
        while (count--) {
            Node* node = pending.front();
            pending.pop();
            for (Node* next : {node->left, node->right, parent[node]})
                if (next && !seen.count(next)) {
                    seen.insert(next);
                    pending.push(next);
                }
        }
    }
    vector<int> answer;
    while (!pending.empty()) {
        answer.push_back(pending.front()->value);
        pending.pop();
    }
    return answer;
}
