int burnTime(Node* root, int start) {
    unordered_map<Node*, Node*> parent;
    queue<Node*> build;
    build.push(root);
    parent[root] = nullptr;
    Node* source = nullptr;
    while (!build.empty()) {
        Node* node = build.front();
        build.pop();
        if (node->value == start)
            source = node;
        for (Node* next : {node->left, node->right})
            if (next) {
                parent[next] = node;
                build.push(next);
            }
    }
    queue<Node*> fire;
    unordered_set<Node*> burned;
    fire.push(source);
    burned.insert(source);
    int minutes = -1;
    while (!fire.empty()) {
        ++minutes;
        int count = fire.size();
        while (count--) {
            Node* node = fire.front();
            fire.pop();
            for (Node* next : {node->left, node->right, parent[node]})
                if (next && !burned.count(next)) {
                    burned.insert(next);
                    fire.push(next);
                }
        }
    }
    return minutes;
}
