bellman-ford-algorithm.code:
#include <bits/stdc++.h>
using namespace std;
struct Edge {
    int from;
    int to;
    int weight;
};
vector<long long> bellmanFord(int vertices, const vector<Edge>& edges, int source) {
    const long long INF = LLONG_MAX / 4;
    vector<long long> distance(vertices, INF);
    distance[source] = 0;
    for (int used = 1; used < vertices; ++used) {
        vector<long long> next = distance;
        for (auto edge : edges)
            if (distance[edge.from] != INF)
                next[edge.to] = min(next[edge.to], distance[edge.from] + edge.weight);
        if (next == distance)
            break;
        distance.swap(next);
    }
    return distance;
}
int main() {
    for (long long value : bellmanFord(3, {{0, 1, 4}, {0, 2, 5}, {1, 2, -2}}, 0))
        cout << value << " ";
    return 0;
