#include <bits/stdc++.h>
using namespace std;
struct Edge {
    int from;
    int to;
    int weight;
};
vector<vector<long long>> allPairs(int vertices, const vector<Edge>& edges) {
    const long long INF = LLONG_MAX / 4;
    vector<vector<long long>> answer(vertices, vector<long long>(vertices, INF));
    for (int source = 0; source < vertices; ++source) {
        answer[source][source] = 0;
        for (int pass = 1; pass < vertices; ++pass) {
            bool changed = false;
            for (auto edge : edges)
                if (answer[source][edge.from] != INF &&
                    answer[source][edge.from] + edge.weight < answer[source][edge.to]) {
                    answer[source][edge.to] = answer[source][edge.from] + edge.weight;
                    changed = true;
                }
            if (!changed)
                break;
        }
    }
    return answer;
}
int main() {
    auto distance = allPairs(3, {{0, 1, 2}, {1, 2, 3}, {0, 2, 10}});
    cout << distance[0][2];
