struct DSU {
    vector<int> parent;
    explicit DSU(int n) : parent(n) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    bool unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b)
            return false;
        parent[b] = a;
        return true;
    }
};
int mst(int vertices, const vector<Edge>& edges) {
    int best = INT_MAX;
    for (int mask = 0; mask < (1 << (int)edges.size()); ++mask)
        if (__builtin_popcount((unsigned)mask) == vertices - 1) {
            DSU dsu(vertices);
            int cost = 0;
            bool tree = true;
            for (int i = 0; i < (int)edges.size(); ++i)
                if (mask & (1 << i)) {
                    tree = tree && dsu.unite(edges[i].from, edges[i].to);
                    cost += edges[i].weight;
                }
            int root = dsu.find(0);
            for (int node = 1; node < vertices; ++node)
                tree = tree && dsu.find(node) == root;
            if (tree)
                best = min(best, cost);
        }
    return best;
}
int main() {
    cout << mst(3, {{0, 1, 1}, {1, 2, 2}, {0, 2, 4}});
    return 0;
}

