#include <bits/stdc++.h>
using namespace std;
void visit(int node, const vector<vector<int>>& graph, vector<int>& time, vector<int>& low,
           vector<bool>& active, stack<int>& pending, int& clock, vector<vector<int>>& components) {
    time[node] = low[node] = clock++;
    pending.push(node);
    active[node] = true;
    for (int next : graph[node])
        if (time[next] < 0) {
            visit(next, graph, time, low, active, pending, clock, components);
            low[node] = min(low[node], low[next]);
        } else if (active[next])
            low[node] = min(low[node], time[next]);
    if (low[node] == time[node]) {
        components.push_back({});
        while (true) {
            int current = pending.top();
            pending.pop();
            active[current] = false;
            components.back().push_back(current);
            if (current == node)
                break;
        }
    }
}
vector<vector<int>> tarjan(const vector<vector<int>>& graph) {
    int clock = 0;
    vector<int> time(graph.size(), -1), low(graph.size());
    vector<bool> active(graph.size());
    stack<int> pending;
    vector<vector<int>> components;
    for (int node = 0; node < (int)graph.size(); ++node)
        if (time[node] < 0)
            visit(node, graph, time, low, active, pending, clock, components);
    return components;
}
int main() {
    cout << tarjan({{1}, {2}, {0, 3}, {}}).size();
    return 0;
}

