#include <bits/stdc++.h>
using namespace std;
bool palindrome(const string& text, int left, int right) {
    while (left < right)
        if (text[left++] != text[right--])
            return false;
    return true;
}
vector<vector<string>> partitions(const string& text) {
    vector<vector<string>> answer;
    int gaps = max(0, (int)text.size() - 1);
    for (int mask = 0; mask < (1 << gaps); ++mask) {
        vector<string> parts;
        int start = 0;
        bool valid = true;
        for (int gap = 0; gap < gaps; ++gap)
            if (mask & (1 << gap)) {
                valid = valid && palindrome(text, start, gap);
                parts.push_back(text.substr(start, gap - start + 1));
                start = gap + 1;
            }
        valid = valid && palindrome(text, start, text.size() - 1);
        parts.push_back(text.substr(start));
        if (valid)
            answer.push_back(parts);
    }
    return answer;
}
int main() {
    cout << partitions("aab").size();
    return 0;
}

