lfu-cache.code:
#include <bits/stdc++.h>
using namespace std;
class LFUCache {
    struct Entry {
        int value;
        int frequency;
        int time;
    };
    int capacity, clock = 0;
    unordered_map<int, Entry> data;

   public:
    explicit LFUCache(int size) : capacity(size) {
    }
    int get(int key) {
        if (!data.count(key))
            return -1;
        Entry& entry = data[key];
        ++entry.frequency;
        entry.time = ++clock;
        return entry.value;
    }
    void put(int key, int value) {
        if (!capacity)
            return;
        if (data.count(key)) {
            data[key].value = value;
            get(key);
            return;
        }
        if ((int)data.size() == capacity) {
            auto victim = min_element(data.begin(), data.end(), [](auto& a, auto& b) {
                return tie(a.second.frequency, a.second.time) <
                       tie(b.second.frequency, b.second.time);
            });
            data.erase(victim);
        }
        data[key] = {value, 1, ++clock};
    }
};
int main() {
    LFUCache cache(2);
    cache.put(1, 10);
    cache.put(2, 20);
    cache.get(1);
    cache.put(3, 30);
    cout << cache.get(2);
    return 0;
}

