#include <bits/stdc++.h>
using namespace std;
double minimizeDistance(const vector<int>& stations, int extra) {
    int intervals = stations.size() - 1;
    vector<int> parts(intervals, 1);
    priority_queue<pair<double, int>> pending;
    for (int i = 0; i < intervals; ++i)
        pending.push({double(stations[i + 1] - stations[i]), i});
    while (extra--) {
        int index = pending.top().second;
        pending.pop();
        ++parts[index];
        pending.push({double(stations[index + 1] - stations[index]) / parts[index], index});
    }
    return pending.top().first;
}
int main() {
    cout << fixed << setprecision(2) << minimizeDistance({1, 2, 3, 4, 5}, 4);
    return 0;
}

