struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
Node* build(const vector<int>& inorder, int inLeft, int inRight, const vector<int>& postorder,
            int postLeft, int postRight) {
    if (inLeft > inRight)
        return nullptr;
    int rootValue = postorder[postRight],
        middle = find(inorder.begin() + inLeft, inorder.begin() + inRight + 1, rootValue) -
                 inorder.begin(),
        leftSize = middle - inLeft;
    Node* root = new Node(rootValue);
    root->left = build(inorder, inLeft, middle - 1, postorder, postLeft, postLeft + leftSize - 1);
    root->right =
        build(inorder, middle + 1, inRight, postorder, postLeft + leftSize, postRight - 1);
    return root;
}
int main() {
    vector<int> inorder = {9, 3, 15, 20, 7}, postorder = {9, 15, 7, 20, 3};
    cout << build(inorder, 0, 4, postorder, 0, 4)->value;
    return 0;
}

