#include <bits/stdc++.h>
using namespace std;
struct DSU {
    vector<int> parent, size;
    explicit DSU(int n) : parent(n), size(n, 1) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    void unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a == b)
            return;
        if (size[a] < size[b])
            swap(a, b);
        parent[b] = a;
        size[a] += size[b];
    }
};
int components(int vertices, const vector<pair<int, int>>& edges) {
    DSU dsu(vertices);
    for (const auto& codeverseItem0 : edges) {
        auto a = codeverseItem0.first;
        auto b = codeverseItem0.second;
        dsu.unite(a, b);
    }
    set<int> roots;
    for (int node = 0; node < vertices; ++node)
        roots.insert(dsu.find(node));
    return roots.size();
}
int main() {
    cout << components(5, {{0, 1}, {1, 2}, {3, 4}});
    return 0;
}

