    stack<int> pending;
    pending.push(start);
    seen[start] = true;
    while (!pending.empty()) {
        int node = pending.top();
        pending.pop();
        order.push_back(node);
        for (auto it = graph[node].rbegin(); it != graph[node].rend(); ++it)
            if (!seen[*it]) {
                seen[*it] = true;
                pending.push(*it);
