#include <bits/stdc++.h>
using namespace std;
struct DSU {
    vector<int> parent;
    explicit DSU(int n) : parent(n) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        return parent[x] == x ? x : parent[x] = find(parent[x]);
    }
    void unite(int a, int b) {
        a = find(a);
        b = find(b);
        if (a != b)
            parent[b] = a;
    }
};
int provinces(const vector<vector<int>>& connected) {
    int n = connected.size();
    DSU dsu(n);
    for (int i = 0; i < n; ++i)
        for (int j = i + 1; j < n; ++j)
            if (connected[i][j])
                dsu.unite(i, j);
    set<int> roots;
    for (int city = 0; city < n; ++city)
        roots.insert(dsu.find(city));
    return roots.size();
}
