#include <bits/stdc++.h>
using namespace std;
int minutesToRot(vector<vector<int>> grid) {
    int rows = grid.size(), columns = grid[0].size(), minutes = 0, moves[5] = {-1, 0, 1, 0, -1};
    while (true) {
        vector<vector<int>> next = grid;
        bool changed = false;
        for (int r = 0; r < rows; ++r)
            for (int c = 0; c < columns; ++c)
                if (grid[r][c] == 2)
                    for (int d = 0; d < 4; ++d) {
                        int nr = r + moves[d], nc = c + moves[d + 1];
                        if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && grid[nr][nc] == 1) {
                            next[nr][nc] = 2;
                            changed = true;
                        }
                    }
        if (!changed)
            break;
        grid.swap(next);
        ++minutes;
    }
    for (auto& row : grid)
        for (int value : row)
            if (value == 1)
                return -1;
    return minutes;
}
int main() {
    cout << minutesToRot({{2, 1, 1}, {1, 1, 0}, {0, 1, 1}});
    return 0;
}

