string alien(const vector<string>& words, int alphabet) {
    vector<vector<int>> graph(alphabet);
    for (int i = 0; i + 1 < (int)words.size(); ++i) {
        int length = min(words[i].size(), words[i + 1].size()), j = 0;
        while (j < length && words[i][j] == words[i + 1][j])
            ++j;
        if (j < length)
            graph[words[i][j] - 'a'].push_back(words[i + 1][j] - 'a');
        else if (words[i].size() > words[i + 1].size())
            return "";
    }
    vector<int> color(alphabet);
    string order;
    for (int ch = 0; ch < alphabet; ++ch)
        if (color[ch] == 0 && !visit(ch, graph, color, order))
            return "";
    reverse(order.begin(), order.end());
    return order;
}
int main() {
    cout << alien({"baa", "abcd", "abca", "cab", "cad"}, 4);
    return 0;
}

