vector<int> shortest(const vector<vector<int>>& graph, int source) {
    vector<int> distance(graph.size(), INT_MAX);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pending;
    distance[source] = 0;
    pending.push({0, source});
    while (!pending.empty()) {
        auto codeverseItem0 = pending.top();
        auto cost = codeverseItem0.first;
        auto node = codeverseItem0.second;
        pending.pop();
        if (cost != distance[node])
            continue;
        for (int next : graph[node])
            if (cost + 1 < distance[next]) {
                distance[next] = cost + 1;
                pending.push({distance[next], next});
            }
    }
    return distance;
}
