#include <bits/stdc++.h>
using namespace std;
bool reachable(const vector<vector<int>>& height, int limit) {
    int rows = height.size(), columns = height[0].size(), moves[5] = {-1, 0, 1, 0, -1};
    queue<pair<int, int>> pending;
    vector<vector<bool>> seen(rows, vector<bool>(columns));
    pending.push({0, 0});
    seen[0][0] = true;
    while (!pending.empty()) {
        auto codeverseItem0 = pending.front();
        auto r = codeverseItem0.first;
        auto c = codeverseItem0.second;
        pending.pop();
        if (r + 1 == rows && c + 1 == columns)
            return true;
        for (int d = 0; d < 4; ++d) {
            int nr = r + moves[d], nc = c + moves[d + 1];
            if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && !seen[nr][nc] &&
                abs(height[r][c] - height[nr][nc]) <= limit) {
                seen[nr][nc] = true;
                pending.push({nr, nc});
            }
        }
    }
    return false;
}
int minimumEffort(const vector<vector<int>>& height) {
    int low = 0, high = 1000000;
    while (low < high) {
        int middle = low + (high - low) / 2;
        if (reachable(height, middle))
            high = middle;
        else
            low = middle + 1;
    }
    return low;
}
int main() {
    cout << minimumEffort({{1, 2, 2}, {3, 8, 2}, {5, 3, 5}});
    return 0;
}

