    int to;
    int price;
};
int cheapest(int cities, const vector<Flight>& flights, int source, int target, int stops) {
    const int INF = 1e9;
    vector<int> cost(cities, INF);
    cost[source] = 0;
    for (int edgeCount = 0; edgeCount <= stops; ++edgeCount) {
        vector<int> next = cost;
        for (auto flight : flights)
            if (cost[flight.from] != INF)
                next[flight.to] = min(next[flight.to], cost[flight.from] + flight.price);
        cost.swap(next);
    }
    return cost[target] == INF ? -1 : cost[target];
}
