int mst(const vector<vector<int>>& weight) {
    int n = weight.size(), answer = 0;
    vector<int> key(n, INT_MAX);
    vector<bool> used(n);
    key[0] = 0;
    for (int step = 0; step < n; ++step) {
        int node = -1;
        for (int i = 0; i < n; ++i)
            if (!used[i] && (node < 0 || key[i] < key[node]))
                node = i;
        used[node] = true;
        answer += key[node];
        for (int next = 0; next < n; ++next)
            if (weight[node][next] >= 0 && !used[next])
                key[next] = min(key[next], weight[node][next]);
    }
    return answer;
}
