vector<vector<string>> mergeAccounts(const vector<vector<string>>& accounts) {
    unordered_map<string, vector<string>> graph;
    unordered_map<string, string> owner;
    for (auto& account : accounts) {
        for (int i = 1; i < (int)account.size(); ++i)
            owner[account[i]] = account[0];
        for (int i = 2; i < (int)account.size(); ++i) {
            graph[account[1]].push_back(account[i]);
            graph[account[i]].push_back(account[1]);
        }
    }
    unordered_set<string> seen;
    vector<vector<string>> answer;
    for (auto& item : owner)
        if (!seen.count(item.first)) {
            vector<string> emails;
            stack<string> pending;
            pending.push(item.first);
            seen.insert(item.first);
            while (!pending.empty()) {
                string email = pending.top();
                pending.pop();
                emails.push_back(email);
                for (auto& next : graph[email])
                    if (!seen.count(next)) {
                        seen.insert(next);
                        pending.push(next);
                    }
            }
            sort(emails.begin(), emails.end());
            emails.insert(emails.begin(), item.second);
            answer.push_back(emails);
        }
    return answer;
}
