#include <bits/stdc++.h>
using namespace std;
bool reachable(const vector<vector<int>>& grid, int water) {
    int n = grid.size(), moves[5] = {-1, 0, 1, 0, -1};
    if (grid[0][0] > water)
        return false;
    queue<pair<int, int>> pending;
    vector<vector<bool>> seen(n, vector<bool>(n));
    pending.push({0, 0});
    seen[0][0] = true;
    while (!pending.empty()) {
        auto codeverseItem0 = pending.front();
        auto r = codeverseItem0.first;
        auto c = codeverseItem0.second;
        pending.pop();
        if (r + 1 == n && c + 1 == n)
            return true;
        for (int d = 0; d < 4; ++d) {
            int nr = r + moves[d], nc = c + moves[d + 1];
            if (nr >= 0 && nr < n && nc >= 0 && nc < n && !seen[nr][nc] && grid[nr][nc] <= water) {
                seen[nr][nc] = true;
                pending.push({nr, nc});
            }
        }
    }
    return false;
}
int swim(const vector<vector<int>>& grid) {
    int low = 0, high = grid.size() * grid.size() - 1;
    while (low < high) {
        int middle = (low + high) / 2;
        if (reachable(grid, middle))
            high = middle;
        else
            low = middle + 1;
    }
    return low;
}
int main() {
    cout << swim({{0, 2}, {1, 3}});
    return 0;
}

