int collect(int row, int first, int second, const vector<vector<int>>& grid) {
    int rows = grid.size(), columns = grid[0].size();
    if (first < 0 || first >= columns || second < 0 || second >= columns)
        return -1000000000;
    int reward = grid[row][first] + (first == second ? 0 : grid[row][second]);
    if (row + 1 == rows)
        return reward;
    int best = -1000000000;
    for (int moveA = -1; moveA <= 1; ++moveA)
        for (int moveB = -1; moveB <= 1; ++moveB)
            best = max(best, collect(row + 1, first + moveA, second + moveB, grid));
    return reward + best;
}
