    int n = text.size();
    vector<vector<int>> dp(n + 1, vector<int>(n + 1));
    for (int i = 1; i <= n; ++i)
        for (int j = 1; j <= n; ++j)
            dp[i][j] = text[i - 1] == reversed[j - 1] ? 1 + dp[i - 1][j - 1]
                                                      : max(dp[i - 1][j], dp[i][j - 1]);
    return dp[n][n];
}
