#include <bits/stdc++.h>
using namespace std;
string scs(const string& first, const string& second) {
    int n = first.size(), m = second.size();
    vector<vector<int>> dp(n + 1, vector<int>(m + 1));
    for (int i = 1; i <= n; ++i)
        for (int j = 1; j <= m; ++j)
            dp[i][j] = first[i - 1] == second[j - 1] ? 1 + dp[i - 1][j - 1]
                                                     : max(dp[i - 1][j], dp[i][j - 1]);
    int i = n, j = m;
    string answer;
    while (i && j) {
        if (first[i - 1] == second[j - 1]) {
            answer += first[i - 1];
            --i;
            --j;
        } else if (dp[i - 1][j] > dp[i][j - 1])
            answer += first[--i];
        else
            answer += second[--j];
    }
    while (i)
        answer += first[--i];
    while (j)
        answer += second[--j];
    reverse(answer.begin(), answer.end());
    return answer;
}
int main() {
    cout << scs("abac", "cab");
    return 0;
}

