bool bitonic(const vector<int>& values) {
    if (values.empty())
        return true;
    int index = 1;
    while (index < (int)values.size() && values[index] > values[index - 1])
        ++index;
    while (index < (int)values.size() && values[index] < values[index - 1])
        ++index;
    return index == (int)values.size();
}
