    pending.push({0, 0, "", initial});
    while (!pending.empty()) {
        State state = move(pending.front());
        pending.pop();
        if (state.row + 1 == n && state.column + 1 == n) {
            answer.push_back(state.path);
            continue;
        }
        for (int d = 0; d < 4; ++d) {
            int nr = state.row + moves[d], nc = state.column + moves[d + 1];
            if (nr >= 0 && nr < n && nc >= 0 && nc < n && maze[nr][nc] && !state.seen[nr][nc]) {
                State next = state;
                next.row = nr;
                next.column = nc;
                next.path += labels[d];
                next.seen[nr][nc] = true;
                pending.push(move(next));
            }
        }
    }
    sort(answer.begin(), answer.end());
    return answer;
}
int main() {
    for (auto& path : routes({{1, 0, 0, 0}, {1, 1, 0, 1}, {1, 1, 0, 0}, {0, 1, 1, 1}}))
        cout << path << " ";
    return 0;
}

