#include <bits/stdc++.h>
using namespace std;
bool explore(const vector<vector<char>>& board, const string& word, int row, int column,
             string& built, vector<vector<bool>>& seen) {
    if (built.size() == word.size())
        return built == word;
    int rows = board.size(), columns = board[0].size(), moves[5] = {-1, 0, 1, 0, -1};
    for (int d = 0; d < 4; ++d) {
        int nr = row + moves[d], nc = column + moves[d + 1];
        if (nr >= 0 && nr < rows && nc >= 0 && nc < columns && !seen[nr][nc]) {
            seen[nr][nc] = true;
            built += board[nr][nc];
            if (explore(board, word, nr, nc, built, seen))
                return true;
            built.pop_back();
            seen[nr][nc] = false;
        }
    }
    return built == word;
}
bool exists(const vector<vector<char>>& board, const string& word) {
    int rows = board.size(), columns = board[0].size();
    for (int r = 0; r < rows; ++r)
        for (int c = 0; c < columns; ++c) {
            vector<vector<bool>> seen(rows, vector<bool>(columns));
            seen[r][c] = true;
            string built(1, board[r][c]);
            if (explore(board, word, r, c, built, seen))
                return true;
        }
    return false;
}
