#include <bits/stdc++.h>
using namespace std;
void enumerate(int index, int remaining, const vector<int>& candidates, vector<int>& current,
               vector<vector<int>>& answer) {
    if (index == (int)candidates.size()) {
        if (remaining == 0)
            answer.push_back(current);
        return;
    }
    int value = candidates[index];
    for (int count = 0; count * value <= remaining; ++count) {
        for (int i = 0; i < count; ++i)
            current.push_back(value);
        enumerate(index + 1, remaining - count * value, candidates, current, answer);
        for (int i = 0; i < count; ++i)
            current.pop_back();
    }
}
int main() {
    vector<int> current;
    vector<vector<int>> answer;
    enumerate(0, 7, {2, 3, 6, 7}, current, answer);
    cout << answer.size();
    return 0;
}

