vector<vector<int>> combinations(const vector<int>& values, int target) {
    set<vector<int>> unique;
    for (int mask = 0; mask < (1 << (int)values.size()); ++mask) {
        vector<int> current;
        int sum = 0;
        for (int bit = 0; bit < (int)values.size(); ++bit)
            if (mask & (1 << bit)) {
                current.push_back(values[bit]);
                sum += values[bit];
            }
        if (sum == target) {
            sort(current.begin(), current.end());
            unique.insert(current);
        }
    }
    return {unique.begin(), unique.end()};
}
