#include <bits/stdc++.h>
using namespace std;
bool solve(vector<vector<char>>& board, array<int, 9>& rows, array<int, 9>& columns,
           array<int, 9>& boxes) {
    int bestRow = -1, bestColumn = -1, bestMask = 0, bestCount = 10;
    for (int r = 0; r < 9; ++r)
        for (int c = 0; c < 9; ++c)
            if (board[r][c] == '.') {
                int mask = (~(rows[r] | columns[c] | boxes[(r / 3) * 3 + c / 3])) & 0x1FF,
                    count = __builtin_popcount((unsigned)mask);
                if (count < bestCount) {
                    bestCount = count;
                    bestRow = r;
                    bestColumn = c;
                    bestMask = mask;
                }
            }
    if (bestRow < 0)
        return true;
    if (bestCount == 0)
        return false;
    int box = (bestRow / 3) * 3 + bestColumn / 3;
    for (int mask = bestMask; mask; mask &= mask - 1) {
        int bit = mask & -mask, digit = __builtin_ctz((unsigned)bit);
        board[bestRow][bestColumn] = char('1' + digit);
        rows[bestRow] |= bit;
        columns[bestColumn] |= bit;
        boxes[box] |= bit;
        if (solve(board, rows, columns, boxes))
            return true;
        rows[bestRow] ^= bit;
        columns[bestColumn] ^= bit;
        boxes[box] ^= bit;
    }
    board[bestRow][bestColumn] = '.';
    return false;
}
int main() {
    vector<vector<char>> board = {{'5', '3', '.', '.', '7', '.', '.', '.', '.'},
                                  {'6', '.', '.', '1', '9', '5', '.', '.', '.'},
                                  {'.', '9', '8', '.', '.', '.', '.', '6', '.'},
                                  {'8', '.', '.', '.', '6', '.', '.', '.', '3'},
                                  {'4', '.', '.', '8', '.', '3', '.', '.', '1'},
                                  {'7', '.', '.', '.', '2', '.', '.', '.', '6'},
                                  {'.', '6', '.', '.', '.', '.', '2', '8', '.'},
                                  {'.', '.', '.', '4', '1', '9', '.', '.', '5'},
                                  {'.', '.', '.', '.', '8', '.', '.', '7', '9'}};
    array<int, 9> rows{}, columns{}, boxes{};
    for (int r = 0; r < 9; ++r)
        for (int c = 0; c < 9; ++c)
            if (board[r][c] != '.') {
                int bit = 1 << (board[r][c] - '1');
                rows[r] |= bit;
                columns[c] |= bit;
                boxes[(r / 3) * 3 + c / 3] |= bit;
            }
    solve(board, rows, columns, boxes);
    cout << board[0][2];
    return 0;
}

