#include <bits/stdc++.h>
using namespace std;
class Trie {
    struct Node {
        unordered_map<char, unique_ptr<Node>> next;
        bool terminal = false;
    };
    Node root;

   public:
    void insert(const string& word) {
        Node* node = &root;
        for (char ch : word) {
            auto& child = node->next[ch];
            if (!child)
                child = make_unique<Node>();
            node = child.get();
        }
        node->terminal = true;
    }
    bool search(const string& word) const {
        const Node* node = &root;
        for (char ch : word) {
            auto it = node->next.find(ch);
            if (it == node->next.end())
                return false;
            node = it->second.get();
        }
        return node->terminal;
    }
    bool startsWith(const string& prefix) const {
        const Node* node = &root;
        for (char ch : prefix) {
            auto it = node->next.find(ch);
            if (it == node->next.end())
                return false;
            node = it->second.get();
        }
        return true;
    }
};
int main() {
    Trie trie;
    trie.insert("apple");
    cout << boolalpha << trie.search("apple") << " " << trie.startsWith("app");
    return 0;
}

implement-trie-ii.code:
#include <bits/stdc++.h>
using namespace std;
class Trie {
    struct Node {
        unordered_map<char, unique_ptr<Node>> next;
        int prefix = 0, terminal = 0;
    };
    Node root;

   public:
    void insert(const string& word) {
        Node* node = &root;
        for (char ch : word) {
            auto& child = node->next[ch];
            if (!child)
                child = make_unique<Node>();
            node = child.get();
            ++node->prefix;
        }
        ++node->terminal;
    }
    int countWordsEqualTo(const string& word) const {
        const Node* node = &root;
        for (char ch : word) {
            auto it = node->next.find(ch);
            if (it == node->next.end())
                return 0;
            node = it->second.get();
        }
        return node->terminal;
    }
    void erase(const string& word) {
        Node* node = &root;
        vector<Node*> path;
        for (char ch : word) {
            auto it = node->next.find(ch);
            if (it == node->next.end())
                return;
            node = it->second.get();
            path.push_back(node);
        }
        if (!node->terminal)
            return;
        --node->terminal;
        for (Node* part : path)
            --part->prefix;
    }
};
int main() {
    Trie trie;
    trie.insert("apple");
    trie.insert("apple");
    trie.erase("apple");
    cout << trie.countWordsEqualTo("apple");
    return 0;
}

