#include <bits/stdc++.h>
using namespace std;
vector<vector<string>> ladders(string begin, string end, const vector<string>& words) {
    unordered_set<string> dictionary(words.begin(), words.end());
    if (!dictionary.count(end))
        return {};
    unordered_map<string, int> distance;
    unordered_map<string, vector<string>> parent;
    queue<string> pending;
    pending.push(begin);
    distance[begin] = 0;
    while (!pending.empty()) {
        string word = pending.front();
        pending.pop();
        string next = word;
        for (int i = 0; i < (int)word.size(); ++i) {
            char saved = next[i];
            for (char ch = 'a'; ch <= 'z'; ++ch) {
                next[i] = ch;
                if (!dictionary.count(next))
                    continue;
                if (!distance.count(next)) {
                    distance[next] = distance[word] + 1;
                    parent[next].push_back(word);
                    pending.push(next);
                } else if (distance[next] == distance[word] + 1)
                    parent[next].push_back(word);
            }
            next[i] = saved;
        }
    }
    vector<vector<string>> answer;
    vector<string> path{end};
    function<void(const string&)> build = [&](const string& word) {
        if (word == begin) {
            auto sequence = path;
            reverse(sequence.begin(), sequence.end());
            answer.push_back(sequence);
            return;
        }
        for (auto& previous : parent[word]) {
            path.push_back(previous);
            build(previous);
            path.pop_back();
        }
    };
    if (distance.count(end))
        build(end);
    return answer;
}
int main() {
    cout << ladders("hit", "cog", {"hot", "dot", "dog", "lot", "log", "cog"}).size();
    return 0;
}

