#include <bits/stdc++.h>
using namespace std;
class QuickFind {
    vector<int> label;

   public:
    explicit QuickFind(int n) : label(n) {
        iota(label.begin(), label.end(), 0);
    }
    int find(int value) const {
        return label[value];
    }
    void unite(int first, int second) {
        int from = label[second], to = label[first];
        if (from == to)
            return;
        for (int& value : label)
            if (value == from)
                value = to;
    }
};
int main() {
    QuickFind dsu(5);
    dsu.unite(0, 1);
    dsu.unite(1, 2);
    cout << boolalpha << (dsu.find(0) == dsu.find(2));
