#include <bits/stdc++.h>
using namespace std;
class SegmentTree {
    int size;
    vector<long long> tree;

   public:
    explicit SegmentTree(const vector<int>& values) : size(values.size()), tree(2 * size) {
        for (int i = 0; i < size; ++i)
            tree[size + i] = values[i];
        for (int i = size - 1; i; --i)
            tree[i] = tree[2 * i] + tree[2 * i + 1];
    }
    void update(int index, int value) {
        for (tree[index += size] = value; index > 1; index /= 2)
            tree[index / 2] = tree[index] + tree[index ^ 1];
    }
    long long query(int left, int right) const {
        long long answer = 0;
        for (left += size, right += size; left < right; left /= 2, right /= 2) {
            if (left & 1)
                answer += tree[left++];
            if (right & 1)
                answer += tree[--right];
        }
        return answer;
    }
};
int main() {
    SegmentTree tree({1, 2, 3, 4});
    tree.update(1, 5);
    cout << tree.query(1, 4);
    return 0;
}

