class Twitter {
    struct Tweet {
        int user;
        int id;
    };
    vector<Tweet> tweets;
    unordered_map<int, unordered_set<int>> following;

   public:
    void postTweet(int user, int tweet) {
        tweets.push_back({user, tweet});
    }
    void follow(int user, int other) {
        following[user].insert(other);
    }
    void unfollow(int user, int other) {
        following[user].erase(other);
    }
    vector<int> getNewsFeed(int user) const {
        vector<int> feed;
        for (auto it = tweets.rbegin(); it != tweets.rend() && feed.size() < 10; ++it)
            if (it->user == user || (following.count(user) && following.at(user).count(it->user)))
                feed.push_back(it->id);
        return feed;
    }
};
int main() {
    Twitter twitter;
    twitter.postTweet(1, 5);
    twitter.follow(1, 2);
    twitter.postTweet(2, 6);
    for (int tweet : twitter.getNewsFeed(1))
        cout << tweet << " ";
