vector<int> postorder(Node* root) {
    vector<int> order;
    stack<Node*> pending;
    if (root)
        pending.push(root);
    while (!pending.empty()) {
        Node* node = pending.top();
        pending.pop();
        order.push_back(node->value);
        if (node->left)
            pending.push(node->left);
        if (node->right)
            pending.push(node->right);
    }
    reverse(order.begin(), order.end());
    return order;
}
