#include <bits/stdc++.h>
using namespace std;
struct Node {
    int value;
    Node* left;
    Node* right;
    explicit Node(int x) : value(x), left(nullptr), right(nullptr) {
    }
};
void graph(Node* node, unordered_map<Node*, vector<Node*>>& edges, vector<Node*>& nodes) {
    if (!node)
        return;
    nodes.push_back(node);
    for (Node* child : {node->left, node->right})
        if (child) {
            edges[node].push_back(child);
            edges[child].push_back(node);
            graph(child, edges, nodes);
        }
}
void explore(Node* node, Node* parent, long long sum,
             const unordered_map<Node*, vector<Node*>>& edges, long long& best) {
    sum += node->value;
    best = max(best, sum);
    auto it = edges.find(node);
    if (it != edges.end())
        for (Node* next : it->second)
            if (next != parent)
                explore(next, node, sum, edges, best);
}
long long maximumPath(Node* root) {
    unordered_map<Node*, vector<Node*>> edges;
    vector<Node*> nodes;
    graph(root, edges, nodes);
    long long best = LLONG_MIN;
    for (Node* start : nodes)
        explore(start, nullptr, 0, edges, best);
    return best;
}
int main() {
    Node root(-10), a(9), b(20), c(15), d(7);
    root.left = &a;
    root.right = &b;
    b.left = &c;
    b.right = &d;
    cout << maximumPath(&root);
    return 0;
}

