        return true;
    queue<Node*> pending;
    pending.push(root);
    while (!pending.empty()) {
        Node* node = pending.front();
        pending.pop();
        if (!node->left && !node->right)
            continue;
        int sum = 0;
        if (node->left) {
            sum += node->left->value;
            pending.push(node->left);
