number-of-ways-to-arrive-at-destination.code:
#include <bits/stdc++.h>
using namespace std;
void explore(int node, int target, long long cost, const vector<vector<pair<int, int>>>& graph,
             vector<bool>& seen, long long& best, long long& ways) {
    if (cost > best)
        return;
    if (node == target) {
        if (cost < best) {
            best = cost;
            ways = 1;
        } else if (cost == best)
            ++ways;
        return;
    }
    seen[node] = true;
    for (const auto& codeverseItem1 : graph[node]) {
        auto next = codeverseItem1.first;
        auto weight = codeverseItem1.second;
        if (!seen[next])
            explore(next, target, cost + weight, graph, seen, best, ways);
    }
    seen[node] = false;
}
long long countPaths(int vertices, const vector<tuple<int, int, int>>& roads) {
    vector<vector<pair<int, int>>> graph(vertices);
    for (const auto& codeverseItem0 : roads) {
        auto a = get<0>(codeverseItem0);
        auto b = get<1>(codeverseItem0);
        auto w = get<2>(codeverseItem0);
        graph[a].push_back({b, w});
        graph[b].push_back({a, w});
    }
    vector<bool> seen(vertices);
    long long best = LLONG_MAX, ways = 0;
    explore(0, vertices - 1, 0, graph, seen, best, ways);
    return ways;
}
int main() {
    cout << countPaths(4, {{0, 1, 1}, {1, 3, 1}, {0, 2, 1}, {2, 3, 1}});
    return 0;
}
